// =====================================================================
// =================== SMART ROBOT AI INJECTION ========================
// =====================================================================
class PlatoProRobot {
    constructor(logic) {
        this.logic = logic;
        this.memory = new Map();
        
        var self = this;
        this.logic.onTurnChange.receive(function() { self.onTurn(); });
        this.logic.onSynchronize.receive(function() { self.onTurn(); });
        this.logic.onRevealSignal.receive(function(e) { self.onReveal(e); });
        this.logic.onGameEnd.receive(function(w) { self.onGameEnd(w); });
        
        plato.log("🤖 [Smart Robot] AI Injected and Ready! Playing like a Pro.");
    }
    
    onTurn() {
        try {
            if (!this.logic.started || this.logic.gameOver) return;
            if (this.logic.localSeat === undefined || this.logic.localSeat < 0) return;
            
            if (this.logic.isTurn(this.logic.localSeat) && this.logic.state === 1) {
                plato.log("🤖 [Smart Robot] My turn! Thinking...");
                var thinkTime = 800 + Math.random() * 1200;
                var self = this;
                plato.setTimer(function() { self.executeProMove(); }, thinkTime);
            }
        } catch(err) {
            plato.log("Robot Error in onTurn: " + err.message);
        }
    }
    
    onReveal(e) {
        try {
            if (e.t === 0 && e.p) {
                this.memory.set(e.c, "PAIRED");
                if (e.seat === this.logic.localSeat && Math.random() > 0.6) {
                    if (typeof P !== 'undefined' && P.reactionsPlugin) {
                        plato.setTimer(function() { P.reactionsPlugin.pushReaction("r6", -1); }, 1000);
                    }
                }
            }
        } catch(err) {}
    }
    
    onGameEnd(winners) {
        try {
            var isWinner = false;
            if (winners && winners[0] && winners[0].includes(this.logic.localSeat)) {
                isWinner = true;
            }
            if (typeof P !== 'undefined' && P.reactionsPlugin) {
                plato.setTimer(function() { 
                    P.reactionsPlugin.pushReaction(isWinner ? "r1" : "r9", -1); 
                }, 1000);
            }
        } catch(err) {}
    }
    
    executeProMove() {
        try {
            if (this.logic.state !== 1) return;
            var targetSeat = this.logic.getLastSeat(this.logic.localSeat);
            var targetHandSize = this.logic.hands[targetSeat].length;
            
            if (targetHandSize <= 0) return;
            
            var hovers = Math.floor(Math.random() * 3) + 1; 
            var self = this;
            
            var doAction = function(hoversLeft) {
                try {
                    if (self.logic.state !== 1 || !self.logic.isTurn(self.logic.localSeat)) return;
                    
                    if (hoversLeft > 0) {
                        var fakeIdx = Math.floor(Math.random() * targetHandSize);
                        self.logic.localMove({ t: 1, i: fakeIdx }); 
                        plato.setTimer(function() { doAction(hoversLeft - 1); }, 300 + Math.random() * 300);
                    } else {
                        var bestIdx = Math.floor(Math.random() * targetHandSize);
                        
                        if (typeof vt !== 'undefined' && vt[targetSeat] && vt[targetSeat].children) {
                            var visualCards = vt[targetSeat].children;
                            for (var i = 0; i < visualCards.length; i++) {
                                var cVal = visualCards[i].value;
                                if (cVal !== -1) {
                                    if ((cVal >> 2) === 1) { 
                                        continue; 
                                    }
                                    bestIdx = i; 
                                    break;
                                }
                            }
                        }
                        
                        plato.log("🤖 [Smart Robot] Pro picking index " + bestIdx);
                        self.logic.localMove({ t: 0, i: bestIdx }); 
                    }
                } catch(err) {}
            };
            
            doAction(hovers);
        } catch(err) {
            plato.log("Robot Error in executeProMove: " + err.message);
        }
    }
}

if (typeof P !== 'undefined') {
    plato.smartRobot = new PlatoProRobot(P);
}
